// // This module selects between two 16-bit wide input signals. When ALUOP is 1, it outputs the second input (BIN); when ALUOP is 0, it outputs the first input (ALU_IN).
module top_module(ALUOP, ALU_IN, BIN, MUXOUT);input ALUOP;

	input [15:0] ALU_IN;
	input [15:0] BIN;

	output [15:0] MUXOUT;

    assign MUXOUT = (ALUOP == 0) ?   BIN : ALU_IN;

endmodule
